        .ddr_rd_axi_ruser(ddr_rd_axi_ruser),
        .ddr_rd_axi_rvalid(ddr_rd_axi_rvalid),
        .ddr_rd_axi_rready(ddr_rd_axi_rready),

        // Bridge ID tracking
        .xbar_bridge_id_ar(ddr_rd_axi_bridge_id_ar),
        .rid_bridge_id(ddr_rd_axi_rid_bridge_id),
        .rid_valid(ddr_rd_axi_rid_valid),

        // Monitor side-band
        .i_mon_time(mon_time_w),
        .monbus_rd_valid(monbus_ddr_rd_0_rd_valid),
        .monbus_rd_ready(monbus_ddr_rd_0_rd_ready),
        .monbus_rd_packet(monbus_ddr_rd_0_rd_packet),
