        .cfg_rd_axi_timeout_mask(cfg_ddr_rd_0_rd_axi_timeout_mask),
        .cfg_rd_axi_compl_mask(cfg_ddr_rd_0_rd_axi_compl_mask),
        .cfg_rd_axi_thresh_mask(cfg_ddr_rd_0_rd_axi_thresh_mask),
        .cfg_rd_axi_perf_mask(cfg_ddr_rd_0_rd_axi_perf_mask),
        .cfg_rd_axi_addr_mask(cfg_ddr_rd_0_rd_axi_addr_mask),
        .cfg_rd_axi_debug_mask(cfg_ddr_rd_0_rd_axi_debug_mask)
    );

    // sram_rd adapter (AXI4, crossbar → external slave)
    sram_rd_adapter u_sram_rd_adapter (
        .aclk(aclk),
        .aresetn(aresetn),

        // Crossbar interface (xbar_sram_rd_axi_*)
        .xbar_sram_rd_axi_arid(xbar_sram_rd_axi_arid),
        .xbar_sram_rd_axi_araddr(xbar_sram_rd_axi_araddr),
        .xbar_sram_rd_axi_arlen(xbar_sram_rd_axi_arlen),
