        .xbar_sram_rd_axi_rready(xbar_sram_rd_axi_rready),

        // External AXI4 interface (sram_rd_axi_*)
        .sram_rd_axi_arid(sram_rd_axi_arid),
        .sram_rd_axi_araddr(sram_rd_axi_araddr),
        .sram_rd_axi_arlen(sram_rd_axi_arlen),
        .sram_rd_axi_arsize(sram_rd_axi_arsize),
        .sram_rd_axi_arburst(sram_rd_axi_arburst),
        .sram_rd_axi_arlock(sram_rd_axi_arlock),
        .sram_rd_axi_arcache(sram_rd_axi_arcache),
        .sram_rd_axi_arprot(sram_rd_axi_arprot),
        .sram_rd_axi_arqos(sram_rd_axi_arqos),
        .sram_rd_axi_arregion(sram_rd_axi_arregion),
        .sram_rd_axi_aruser(sram_rd_axi_aruser),
        .sram_rd_axi_arvalid(sram_rd_axi_arvalid),
        .sram_rd_axi_arready(sram_rd_axi_arready),
        .sram_rd_axi_rid(sram_rd_axi_rid),
        .sram_rd_axi_rdata(sram_rd_axi_rdata),
        .sram_rd_axi_rresp(sram_rd_axi_rresp),
        .sram_rd_axi_rlast(sram_rd_axi_rlast),
        .sram_rd_axi_ruser(sram_rd_axi_ruser),
        .sram_rd_axi_rvalid(sram_rd_axi_rvalid),
        .sram_rd_axi_rready(sram_rd_axi_rready),

        // Bridge ID tracking
        .xbar_bridge_id_ar(sram_rd_axi_bridge_id_ar),
        .rid_bridge_id(sram_rd_axi_rid_bridge_id),
        .rid_valid(sram_rd_axi_rid_valid),

        // Monitor side-band
        .i_mon_time(mon_time_w),
        .monbus_rd_valid(monbus_sram_rd_1_rd_valid),
        .monbus_rd_ready(monbus_sram_rd_1_rd_ready),
        .monbus_rd_packet(monbus_sram_rd_1_rd_packet),
        .monbus_rd_timestamp(monbus_sram_rd_1_rd_timestamp),
        .cfg_rd_monitor_enable(cfg_sram_rd_1_rd_monitor_enable),
        .cfg_rd_error_enable(cfg_sram_rd_1_rd_error_enable),
        .cfg_rd_timeout_enable(cfg_sram_rd_1_rd_timeout_enable),
        .cfg_rd_perf_enable(cfg_sram_rd_1_rd_perf_enable),
        .cfg_rd_timeout_cycles(cfg_sram_rd_1_rd_timeout_cycles),
        .cfg_rd_latency_threshold(cfg_sram_rd_1_rd_latency_threshold),
        .cfg_rd_axi_pkt_mask(cfg_sram_rd_1_rd_axi_pkt_mask),
        .cfg_rd_axi_err_select(cfg_sram_rd_1_rd_axi_err_select),
        .cfg_rd_axi_error_mask(cfg_sram_rd_1_rd_axi_error_mask),
        .cfg_rd_axi_timeout_mask(cfg_sram_rd_1_rd_axi_timeout_mask),
        .cfg_rd_axi_compl_mask(cfg_sram_rd_1_rd_axi_compl_mask),
        .cfg_rd_axi_thresh_mask(cfg_sram_rd_1_rd_axi_thresh_mask),
        .cfg_rd_axi_perf_mask(cfg_sram_rd_1_rd_axi_perf_mask),
        .cfg_rd_axi_addr_mask(cfg_sram_rd_1_rd_axi_addr_mask),
        .cfg_rd_axi_debug_mask(cfg_sram_rd_1_rd_axi_debug_mask)
    );

    // ============================================================
    // Monitor aggregator -- 3 client(s) -> arbiter -> axil_group
    // ============================================================
    logic                                  mon_arb_monbus_valid_in     [3];
    logic                                  mon_arb_monbus_ready_in     [3];
    monitor_common_pkg::monitor_packet_t   mon_arb_monbus_packet_in    [3];
    monitor_common_pkg::monbus_timestamp_t mon_arb_monbus_timestamp_in [3];
    assign mon_arb_monbus_valid_in[0]     = monbus_cpu_rd_0_rd_valid;
    assign monbus_cpu_rd_0_rd_ready = mon_arb_monbus_ready_in[0];
    assign mon_arb_monbus_packet_in[0]    = monbus_cpu_rd_0_rd_packet;
    assign mon_arb_monbus_timestamp_in[0] = monbus_cpu_rd_0_rd_timestamp;
    assign mon_arb_monbus_valid_in[1]     = monbus_ddr_rd_0_rd_valid;
    assign monbus_ddr_rd_0_rd_ready = mon_arb_monbus_ready_in[1];
    assign mon_arb_monbus_packet_in[1]    = monbus_ddr_rd_0_rd_packet;
    assign mon_arb_monbus_timestamp_in[1] = monbus_ddr_rd_0_rd_timestamp;
    assign mon_arb_monbus_valid_in[2]     = monbus_sram_rd_1_rd_valid;
    assign monbus_sram_rd_1_rd_ready = mon_arb_monbus_ready_in[2];
    assign mon_arb_monbus_packet_in[2]    = monbus_sram_rd_1_rd_packet;
    assign mon_arb_monbus_timestamp_in[2] = monbus_sram_rd_1_rd_timestamp;

    monbus_arbiter #(
        .CLIENTS            (3),
        .INPUT_SKID_ENABLE  (1),
        .OUTPUT_SKID_ENABLE (1),
        .INPUT_SKID_DEPTH   (2),
        .OUTPUT_SKID_DEPTH  (2)
    ) u_mon_arbiter (
        .axi_aclk            (aclk),
        .axi_aresetn         (aresetn),
        .block_arb           (1'b0),
        .monbus_valid_in     (mon_arb_monbus_valid_in),
        .monbus_ready_in     (mon_arb_monbus_ready_in),
        .monbus_packet_in    (mon_arb_monbus_packet_in),
        .monbus_timestamp_in (mon_arb_monbus_timestamp_in),
        .monbus_valid        (mon_arb_monbus_valid),
        .monbus_ready        (mon_arb_monbus_ready),
        .monbus_packet       (mon_arb_monbus_packet),
        .monbus_timestamp    (mon_arb_monbus_timestamp),
        /* verilator lint_off PINCONNECTEMPTY */
        .grant_valid         (),
        .grant               (),
        .grant_id            (),
        .last_grant          ()
        /* verilator lint_on PINCONNECTEMPTY */
    );

    monbus_axil_group #(
        .FIFO_DEPTH_ERR    (64),
        .FIFO_DEPTH_WRITE  (32),
        .ADDR_WIDTH        (32),
        .S_AXIL_DATA_WIDTH (64),
        // S_AXIL_DATA_WIDTH=64: the unified group drains one
        // err_fifo entry ({packet[127:0], source_ts[63:0]} = 192 bits)
        // over three 64-bit reads via an internal slice counter.
        // M_AXIL_DATA_WIDTH defaults to 64 — module emits two 64-bit beats
        // per 128-bit packet plus optional timestamp beats per cfg_ts_append_mode.
        .NUM_PROTOCOLS     (3)
    ) u_mon_axil_group (
        .axi_aclk          (aclk),
        .axi_aresetn       (aresetn),
        // Arbiter output as the single monbus input + side-band timestamp
        .monbus_valid      (mon_arb_monbus_valid),
        .monbus_ready      (mon_arb_monbus_ready),
        .monbus_packet     (mon_arb_monbus_packet),
        .monbus_timestamp  (mon_arb_monbus_timestamp),
        // Free-running timestamp shared with every wrapper's i_mon_time
        .mon_time_out      (mon_time_w),
        // Timestamp append config: driven from bridge-top inputs so
        // each SoC integrator chooses whether to append source / arrival /
        // both / neither. Default (cocotb-undriven) is 0 / 00 -> packets
        // only, 2 beats per record -- which is what the bridge cocotb
        // capture test's pair-grouping assumes.
        .cfg_ts_append_enable (cfg_mon_group_ts_append_enable),
        .cfg_ts_append_mode   (cfg_mon_group_ts_append_mode),
        // AXIL slave
        .s_axil_arvalid      (s_mon_axil_arvalid),
        .s_axil_arready      (s_mon_axil_arready),
        .s_axil_araddr      (s_mon_axil_araddr),
        .s_axil_arprot      (s_mon_axil_arprot),
        .s_axil_rvalid      (s_mon_axil_rvalid),
        .s_axil_rready      (s_mon_axil_rready),
        .s_axil_rdata      (s_mon_axil_rdata),
        .s_axil_rresp      (s_mon_axil_rresp),
        // AXIL master
        .m_axil_awvalid      (m_mon_axil_awvalid),
        .m_axil_awready      (m_mon_axil_awready),
